            json j = b.to_json();
            Block back = Block::from_json(j);
            check(back.consensus_mode == ConsensusMode::BFT,
                  "BFT block: consensus_mode round-trip");
            check(back.bft_proposer == "alice",
                  "BFT block: bft_proposer round-trip");
